        // Faza 34 — CRIT-02 Fix: Ne lovimo izjem tihoma z emitiranjem praznega stanja.
        // Propagiraj napako navzgor — klicatelji (ViewModel catch bloki) upravljajo UI napake.
        emit(repository.getGamificationState())
    }

    // ─────────────────────────────────────────────────────────────────────────
