        }
    }

    suspend fun checkAndSyncBadgesOnStartup(): List<String> = emptyList()

    /**
     * Faza 4b / 21: Uporabnik je opravil raztezanje na rest dnevu.
     *
     * Server-side guard: če je danes že "WORKOUT_DONE" ali "REST_WORKOUT_DONE",
     * akcija ni dovoljena — vrne obstoječi streak brez spremembe.
     *
     * Faza 21: Kliče moveToNextDay(REST_DAY_DONE) namesto starih updateStreak() + awardXP().
     *
     * @return Novi streak po posodobitvi (ali obstoječi če akcija ni dovoljena).
     */
    suspend fun restDayInitiated(): Int {
        // Faza 32.9 — BUG-04 Fix: getTodayStatus napaka propagira navzgor.
        // Ne defaultiramo na WORKOUT_PENDING ob auth/network napaki — to bi
        // dovolilo raztezanje ko je bil workout danes morda že opravljen.
        val todayStatus = repository.getTodayStatus()

        // Guard: redni trening je danes že opravljen → raztezanje ni dovoljeno
        if (todayStatus == UserDayStatus.WORKOUT_DONE || todayStatus == UserDayStatus.REST_WORKOUT_DONE) {
            // Faza 32.9 — BUG-04 Fix: Odstranjeno runCatching { }.getOrDefault(0).
            // Če getCurrentStreak() spodleti, izjema propagira do CompleteRestDay
            // catch bloka v ViewModel-u → ShowSnackbar namesto streak=0 v UI.
            return repository.getCurrentStreak()
        }

        // REST_DAY_DONE = streak+1, plan_day nespremenjen, +10 XP
        val newStreak = repository.moveToNextDay(
            newStatus      = UserDayStatus.REST_DAY_DONE,
            xpToBeAwarded  = 10,
            xpReason       = "REST_DAY",
            caloriesBurned = 0.0,
            incrementPlanDay = false
        )
        // Faza 32.9 — BUG-04 Fix: De-dup (newStreak==0) ne pokliče getCurrentStreak()
        // z nevarnim getOrDefault(0). Namesto tega vrnemo newStreak direktno:
        //   newStreak > 0 → uspešna posodobitev, vrnemo jo
        //   newStreak == 0 → de-dup (dan je bil že zaključen), vrnemo 0 →
        //     ViewModel-ov takeIf { it > 0 } bo padel na fallback iz current.streakDays
        //   newStreak == -1 → Firestore napaka, vrnemo -1 →
        //     ViewModel-ov takeIf { it > 0 } bo pravilno filtiral
        return newStreak
    }

    /** Worker (ob polnoči) pozove streak check za včerajšnji dan. */
    suspend fun executeMidnightStreakCheck() = repository.runMidnightStreakCheck()
}

package com.example.myapplication.domain.usecase

import com.example.myapplication.domain.model.BodyMetrics
import com.example.myapplication.domain.repository.WorkoutStatsRepository
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.channelFlow

/**
 * GetBodyMetricsUseCase — reaktivni domenski use case za branje fitness metrik.
 *
 * Faza 21: todayStatus je zdaj UserDayStatus (tipsko-varni enum).
 * Faza 32.9 — BUG-05 Fix: Prenovljeno iz one-shot flow{} v channelFlow, ki zbira
 * iz reaktivne Firestore poslušalnice [WorkoutStatsRepository.observeWorkoutStats].
 * Ob vsaki spremembi Firestore dokumenta UI samodejno prejme svežo vrednost —
 * brez ponovnega klica LoadMetrics.
 *
 * BUG-01 Fix: Null snapshot in Firestore napaka sta EKSPLICITNO propagirana prek
 * [BodyMetrics.errorMessage] — nobenih tihih padcev na hardkodirane privzete vrednosti.
 */
class GetBodyMetricsUseCase(
    private val statsRepo: WorkoutStatsRepository
) {
    fun invoke(email: String): Flow<BodyMetrics> = channelFlow {
        // Takoj prikaži nalaganje
        send(BodyMetrics(isLoading = true))

        try {
            // Zbieramo reaktivni tok iz Firestore poslušalnice
            statsRepo.observeWorkoutStats(email).collect { stats ->
                if (stats != null) {
                    // Uspešno mapiranje → pravi podatki
                    send(BodyMetrics(
                        streakDays             = stats.streakDays,
                        streakFreezes          = stats.streakFreezes,
                        weeklyDone             = stats.weeklyDone,
                        weeklyTarget           = stats.weeklyTarget,
                        planDay                = stats.planDay,
                        totalWorkoutsCompleted = stats.totalWorkoutsCompleted,
                        isWorkoutDoneToday     = stats.todayStatus.isDoneToday,
                        dailyKcal              = stats.dailyKcal.takeIf { it > 0 }
                                                 ?: statsRepo.getDailyCalories(),
                        todayIsRest            = stats.todayIsRest,
                        todayStatus            = stats.todayStatus,
                        isLoading              = false
                    ))
                } else {
                    // Faza 32.9 — BUG-01 Fix: Dokument ne obstaja ali ni avtenticiranega
                    // uporabnika. NE uporabimo tihega SharedPrefs fallback-a z hardkodiranimi
                    // vrednostmi (streak=0, weeklyDone=0). Namesto tega propagiramo jasno
                    // napako, ki jo UI prikaže kot ShowSnackbar.
                    send(BodyMetrics(
                        errorMessage = "Failed to sync with server — check connection",
                        isLoading    = false
                    ))
                }
            }
        } catch (e: Exception) {
            // Firestore napaka (network, auth) ali close(error) iz callbackFlow
            // propagira kot BodyMetrics z dejanskim sporočilom — brez hardkodiranih ničel
            send(BodyMetrics(
                errorMessage = e.message ?: "Unknown sync error",
                isLoading    = false
            ))
        }
    }
}

package com.example.myapplication.domain.usecase

import com.example.myapplication.domain.model.BodyMetrics
import com.example.myapplication.domain.repository.WorkoutStatsRepository
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.channelFlow

/**
 * GetBodyMetricsUseCase — reaktivni domenski use case za branje fitness metrik.
 *
 * Faza 21: todayStatus je zdaj UserDayStatus (tipsko-varni enum).
 * Faza 32.9 — BUG-05 Fix: Prenovljeno iz one-shot flow{} v channelFlow, ki zbira
 * iz reaktivne Firestore poslušalnice [WorkoutStatsRepository.observeWorkoutStats].
 * Ob vsaki spremembi Firestore dokumenta UI samodejno prejme svežo vrednost —
 * brez ponovnega klica LoadMetrics.
 *
 * BUG-01 Fix: Null snapshot in Firestore napaka sta EKSPLICITNO propagirana prek
 * [BodyMetrics.errorMessage] — nobenih tihih padcev na hardkodirane privzete vrednosti.
 */
class GetBodyMetricsUseCase(
    private val statsRepo: WorkoutStatsRepository
) {
    fun invoke(email: String): Flow<BodyMetrics> = channelFlow {
        // Takoj prikaži nalaganje
        send(BodyMetrics(isLoading = true))

        try {
            // Faza 34 — MED-04 Fix: getDailyCalories() se kešira ENKRAT pred collect zanko.
            // Prejšnji klic `statsRepo.getDailyCalories()` znotraj collect bloka je izvajal
            // SharedPreferences I/O operacijo ob VSAKEM Firestore eventu — ponavljajoče sinhrone I/O.
            val cachedDailyKcal = statsRepo.getDailyCalories()

            // Zbieramo reaktivni tok iz Firestore poslušalnice
            statsRepo.observeWorkoutStats(email).collect { stats ->
                if (stats != null) {
                    // Uspešno mapiranje → pravi podatki
                    send(BodyMetrics(
                        streakDays             = stats.streakDays,
                        streakFreezes          = stats.streakFreezes,
                        weeklyDone             = stats.weeklyDone,
                        weeklyTarget           = stats.weeklyTarget,
                        planDay                = stats.planDay,
                        totalWorkoutsCompleted = stats.totalWorkoutsCompleted,
                        isWorkoutDoneToday     = stats.todayStatus.isDoneToday,
                        dailyKcal              = stats.dailyKcal.takeIf { it > 0 }
                                                 ?: cachedDailyKcal,  // enkrat keširan vrednost
                        todayIsRest            = stats.todayIsRest,
                        todayStatus            = stats.todayStatus,
                        isLoading              = false
                    ))
                } else {
                    // Faza 32.9 — BUG-01 Fix: Dokument ne obstaja ali ni avtenticiranega
                    // uporabnika. NE uporabimo tihega SharedPrefs fallback-a z hardkodiranimi
                    // vrednostmi (streak=0, weeklyDone=0). Namesto tega propagiramo jasno
                    // napako, ki jo UI prikaže kot ShowSnackbar.
                    send(BodyMetrics(
                        errorMessage = "Failed to sync with server — check connection",
                        isLoading    = false
                    ))
                }
            }
        } catch (e: Exception) {
            // Firestore napaka (network, auth) ali close(error) iz callbackFlow
            // propagira kot BodyMetrics z dejanskim sporočilom — brez hardkodiranih ničel
            send(BodyMetrics(
                errorMessage = e.message ?: "Unknown sync error",
                isLoading    = false
            ))
        }
    }
}

package com.example.myapplication.domain.usecase

import com.example.myapplication.domain.gamification.ManageGamificationUseCase
import com.example.myapplication.domain.gamification.WorkoutCompletionResult
import com.example.myapplication.domain.repository.WorkoutRepository
import kotlinx.datetime.Clock
import kotlinx.datetime.TimeZone
import kotlinx.datetime.toLocalDateTime

class UpdateBodyMetricsUseCase(
    private val workoutRepo: WorkoutRepository,
    private val gamificationUseCase: ManageGamificationUseCase
    // settingsRepo odstranjen — Global Audit Faza 13.3: bm_prefs ni več SSOT za streak/planDay
) {
    suspend operator fun invoke(
        email: String,
        totalKcal: Int,
        totalTimeMin: Double,
        exercisesCount: Int,
        planDay: Int,
        isExtra: Boolean,
        exerciseResults: List<Map<String, Any>>,
        /** Fokus mišic te seje — za fetchLastSessionForFocus() v Fazi 12. */
        focusAreas: List<String> = emptyList(),
        /** FIX: Extra workout na rest dan = samo bonus XP, brez streak posodobitve. */
        isRestDay: Boolean = false
    ): Result<WorkoutCompletionResult?> {
        return try {
            val tz = TimeZone.currentSystemDefault()
            val now = Clock.System.now()
            val hour = now.toLocalDateTime(tz).hour
            val timestamp = now.toEpochMilliseconds()

            // 1. Pridobivanje nagrad (XP, Early Bird, Critical Hit) + Faza 8: Unified Streak Engine
            // isRestDay = isExtra && isRestDay → extra workout na rest dnevu = samo XP, brez streak
            // incrementPlanDay = !isExtra → extra workout ne napreduje plan_day
            val res = gamificationUseCase.recordWorkoutCompletion(
                caloriesBurned   = totalKcal.toDouble(),
                hour             = hour,
                isRestDay        = isRestDay && isExtra,
                incrementPlanDay = !isExtra,
                currentPlanDay   = planDay          // Faza 23: za optimistični newPlanDay izračun
            )

            // 2. Priprava podatkov (BREZ FIREBASE IMPORTA)
            val workoutDoc = mutableMapOf(
                "timestamp" to timestamp,
                "type" to if (isExtra) "extra" else "regular",
                "totalKcal" to totalKcal,
                "totalTimeMin" to totalTimeMin,
                "exercisesCount" to exercisesCount,
                "planDay" to planDay,
                "exercises" to exerciseResults,
                // Faza 12: focusAreas za fetchLastSessionForFocus() iskanje
                "focusAreas" to focusAreas
            )

            // 3. Shranjevanje v bazo
            workoutRepo.saveWorkoutSession(email, workoutDoc)

            // 3b. [Faza 8 — Unified Streak Engine] Streak je zdaj v celoti v ManageGamificationUseCase
            //     → recordWorkoutCompletion() → repository.processWorkoutCompletion()
            //     UserProfileManager.updateUserProgressAfterWorkout() je DEPRECATED no-op.

            // 4–6. Ostalo nespremenjeno (XP, burnedCalories bridge so v ManageGamificationUseCase)

            Result.success(res)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

package com.example.myapplication.domain.usecase

import com.example.myapplication.domain.gamification.ManageGamificationUseCase
import com.example.myapplication.domain.gamification.WorkoutCompletionResult
import kotlinx.datetime.Clock
import kotlinx.datetime.TimeZone
import kotlinx.datetime.toLocalDateTime

/**
 * Faza 34 — CRIT-03 Refaktor: workoutRepo odvisnost ODSTRANJENA.
 *
 * Workout session dokument se zdaj zapisuje znotraj iste Firestore transakcije
 * kot gamification posodobitev (streak, XP, plan_day) prek
 * `gamificationUseCase.recordWorkoutCompletion(workoutSessionDoc = ...)`.
 *
 * Zagotavlja all-or-nothing atomarnost: ali gamification + seja uspeta skupaj,
 * ali nobena — odpravlja delno korupcijo stanja (gamification OK, seja izgubljena).
 */
class UpdateBodyMetricsUseCase(
    private val gamificationUseCase: ManageGamificationUseCase
) {
    suspend operator fun invoke(
        email: String,
        totalKcal: Int,
        totalTimeMin: Double,
        exercisesCount: Int,
        planDay: Int,
        isExtra: Boolean,
        exerciseResults: List<Map<String, Any>>,
        /** Fokus mišic te seje — za fetchLastSessionForFocus() v Fazi 12. */
        focusAreas: List<String> = emptyList(),
        /** FIX: Extra workout na rest dan = samo bonus XP, brez streak posodobitve. */
        isRestDay: Boolean = false
    ): Result<WorkoutCompletionResult?> {
        return try {
            val tz = TimeZone.currentSystemDefault()
            val now = Clock.System.now()
            val hour = now.toLocalDateTime(tz).hour
            val timestamp = now.toEpochMilliseconds()

            // Faza 34 — CRIT-03: Workout session dokument sestavimo PRED klicem gamification,
            // da ga posredujemo v isto Firestore transakcijo (atomarni zapis).
            val workoutDoc = mutableMapOf<String, Any>(
                "timestamp"      to timestamp,
                "type"           to if (isExtra) "extra" else "regular",
                "totalKcal"      to totalKcal,
                "totalTimeMin"   to totalTimeMin,
                "exercisesCount" to exercisesCount,
                "planDay"        to planDay,
                "exercises"      to exerciseResults,
                // Faza 12: focusAreas za fetchLastSessionForFocus() iskanje
                "focusAreas"     to focusAreas
            )

            // 1. Gamification (XP, streak, plan_day) + atomarni zapis seje v isti transakciji.
            //    isRestDay = isExtra && isRestDay → extra workout na rest dnevu = samo XP, brez streak
            //    incrementPlanDay = !isExtra → extra workout ne napreduje plan_day
            val res = gamificationUseCase.recordWorkoutCompletion(
                caloriesBurned    = totalKcal.toDouble(),
                hour              = hour,
                isRestDay         = isRestDay && isExtra,
                incrementPlanDay  = !isExtra,
                currentPlanDay    = planDay,          // Faza 23: za optimistični newPlanDay izračun
                workoutSessionDoc = workoutDoc        // Faza 34: atomarni zapis v isti transakciji
            )

            // 2. Ločeni workoutRepo.saveWorkoutSession() klic ODSTRANJEN — seja je atomarno
            //    zapisana znotraj moveToNextDay() transakcije zgoraj (Faza 34 — CRIT-03).

            Result.success(res)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

